export type SuggestedQuestion = {
  question_id?: number;
  question: string;
  source?: "llm_initial" | "user_query";
  timestamp?: string;
  answer?: string | null;
  image_query?: string;
  image_url?: string;
  image_source_url?: string;
};

/** One document/source ingested into the active corpus. */
export type IngestedDoc = {
  docId: string;
  corpusId: string;
  preview: string;
  chunks: number;
  /** Persisted rows loaded from the backend use 0 because list has no timestamp. */
  at: number;
  /** Aurity-style starter questions generated by the backend LLM on ingest. */
  suggestedQuestions: SuggestedQuestion[];
};

export type DocumentListPayload = {
  corpus_id: string;
  documents: {
    doc_id: string;
    chunk_count: number;
    status: string;
    suggested_questions?: SuggestedQuestion[];
  }[];
};

export type IngestPayload = {
  chunks?: number;
  suggested_questions?: SuggestedQuestion[];
};
